\left(\frac{1}{4}\right)^{2x+8} &= (4^{-1})^{2x+8} = 4^{-(2x+8)} \\
&= \left(4^{2}\right)^{-(x+4)} = (16)^{-(x+4)} \\
&= (16)^{2x+5} \\
